var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이면세계는 위험하지만 이터니움처럼 우리에게 이로운 것도 있습니다.","JPN":"裏世界は危険ですが、エタニウムのように、私たちにとってメリットになる物もあります。","ENG":"The Counterside may be dangerous, but there are things like Eternium that are beneficial to us.","TWN":"雖說異界十分危險，但也有能晶等對於人類有益之物。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국에선 이면세계의 자원을 연구하는 다양한 미래지향성 프로젝트를 지원하고 있는데,","JPN":"管理局では、裏世界の資源を研究する\\n様々な未来志向のプロジェクトを支援しています。","ENG":"The Administration supports various experimental projects that study resources from the Counterside,","TWN":"管理局下有諸多面向未來的異界資源研究專案，"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중 하나가 이면세계에서 얻을 수 있는 대체식량을 연구하는 프로젝트죠.","JPN":"その中の1つが、裏世界で得られる代替食糧を研究するプロジェクトです。","ENG":"among which is alternative food research.","TWN":"其中有項目為針對可從異界獲取代用糧的研究。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"최근까지 성과가 지지부진했었으나, 얼마 전에 좋은 소식이 생겼습니다.","JPN":"長らく成果がなかったプロジェクトですが、最近良い知らせがありました。","ENG":"There hasn't been much progress in this field until recently.","TWN":"雖專案成果至今未有進展，但不久前傳來捷報。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"바로 이면세계에서 식용이 가능한 열매가 발견됐다는 겁니다.","JPN":"裏世界で食用の実が発見されたのです。","ENG":"An edible fruit was found in the Counterside.","TWN":"在異界發現了可食用的果實。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"이 열매는 이면세계에서 자라는 열매로 카카오의 쓴맛과 꿀의 달콤함을 동시에 갖고 있어 초콜릿으로 만들 때 설탕을 넣지 않아도 됩니다.","JPN":"これは裏世界で育つ実で、カカオの苦みとハチミツの甘さを兼ね備えており、\\nチョコレートを作る際に砂糖を入れる必要がありません。","ENG":"This fruit, indigenous to the Counterside, provides both the bitterness of cacao and the sweetness of honey, allowing chocolate to be made without sugar.","TWN":"這種果實生長在異界，兼具可可豆的苦味與蜂蜜的甜味，用它做巧克力時無須另加砂糖。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"한 뿌리에서 열매가 딱 하나만 열린다는 특징 때문에 학계에선 솔로카오라는 별칭이 붙어 있는데요.","JPN":"1つの根から実が1つしか実らないという特徴から、\\n学会では『ソロカオ』と呼ばれています。","ENG":"And because only one fruit grows out of each root, the scientific community calls it Solocao.","TWN":"因一株只能結一果，所以學界為它取別稱為“獨株可可”。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"침식관련 성분은 전혀 검출되지 않았으며, 내부 시식단의 평도 아주 호평입니다.","JPN":"侵食関連の成分はまったく検出されず、内部の試食団からも良い評価を得ています。","ENG":"It has zero Corruption-related substances in it, and been received well among our internal taste testers.","TWN":"它檢測不出侵蝕壁相關成分，內部人員試吃後也給予好評。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 맛이 좋다곤 해도, 이면세계에서 나온 열매를 먹는 것에 대한 일반인들의 거부감을 없애지 않으면 안 되겠죠.","JPN":"しかし、いくら美味しいとはいえ、\\n裏世界の実を食べるという行為に対する嫌悪感を抱く人も多く、それを払拭する必要があります。","ENG":"But no matter how good it tastes, it's no use if it's rejected by the public, who might think it's too dangerous to eat anything from the Counterside.","TWN":"雖口感優質，仍需消除一般民眾對食用異界果實的抗拒心理。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 마침 곧 다가올 발렌타인 데이를 맞이하여 이 솔로카오로 만든 초콜릿을 이용해, 거리 나눔 행사를 진행할 예정입니다.","JPN":"そこで、バレンタインデーにこのソロカオで作ったチョコレートを\\n配るイベントを行う予定です。","ENG":"So, on this Valentine's Day, we're planning to hold a street giveaway event with chocolate made from Solocao.","TWN":"正值情人節前夕，因此管理局打算以獨株可可做成的巧克力開展街邊食物分享活動。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"이에 따라 관리국은 본 행사가 성공적으로 진행될 수 있도록 아래 본 공문을 수령한 태스크포스 및 카운터 여러분에게 최대한의 협력을 요청하는 바입니다.","JPN":"よって、管理局は本イベントが成功するように、\\n下記のタスクフォースカンパニーおよびカウンターの皆様に、できる限りの協力を要請します。","ENG":"The Administration would like to ask full cooperation from all TASKFORCE companies and Counters who have received this notice to ensure the success of this event.","TWN":"由此，管理局為成功開展這次活動，要求收到本公文的諸位特遣人員及制裁者進行盡可能的協作。"},"stage":{"bg":"SOLOCAO","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"......라고 하네요.","JPN":"……だそうです。","ENG":"... So the notice says.","TWN":"……它這樣寫著。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"협력이 아니라 압력이겠지......","JPN":"協力じゃなくて圧力だな……","ENG":"Cooperation? You mean, pressure.","TWN":"什麼協作，這分明是壓迫吧……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 관리국 협조 공문이라는 게 항상 그런 식이죠.","JPN":"まあ、管理局の協力要請公文書は、いつもこうですから。","ENG":"Well, the Administration's cooperation notices always include some persuasion.","TWN":"不過管理局的所謂協作公文一直都是這樣的吧。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"괜히 게으름 부리다가 행사 감독관에게 걸려서 징계라도 받으면 가만두지 않겠다고 수연이가 으르렁거리던데요?","JPN":"サボってるところをイベントの監督官に見つかって、\\n懲戒を受けたりしたらタダじゃおかないって、カナミが言ってましたよ？","ENG":"Sooyeon is determined to punish anyone who gets caught lazing around by the Event Supervisor, though.","TWN":"李秀妍還曾對我咆哮過，如果因偷懶被活動監督抓到挨了罰，一定不會放過我？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"자, 그럼 방금 들으신 것처럼 여러분이 오늘 이 자리에 모인 건, 관리국 나눔 행사에 쓰일 솔로카오를 채집하기 위해서예요.","JPN":"さあ、皆さんにお集まりいただいたのは、\\nご存じの通り、管理局のイベントで使われるソロカオを採取するためです。","ENG":"Now, as you just heard, we gathered everyone here today to harvest Solocaos that will be used for the Administration's giveaway event.","TWN":"好的，就像各位剛才所聽到的，將大家聚到這裡是為了採集管理局分享活動要用到的獨株可可。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까, 고작 열매나 따라고 주말에 사람을 부른 거야?","JPN":"つまり、たかが実を採るために呼ばれたってわけ？","ENG":"So, you brought us in, on the weekend, just to pick fruits?","TWN":"所以呢，就為了個果子週末把人叫來嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"......고작이 아닙니다! 미래의 대체식량을 대중화하기 위한 중요한 첫걸음이죠!","JPN":"……たかがではありません！\\n未来の代替食糧を拡散させるための、大事な一歩です！","ENG":"They aren't just fruits! They're our first step toward popularizing alternative food sources for the future!","TWN":"……不是“就為”！是為將來代用糧大眾化邁出的重要的第一步才對！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"까, 깜짝이야! 당신은 또 누구야?","JPN":"び、びっくりした！　……あなた誰？","ENG":"W-whoa! Who the hell are you?","TWN":"呀，嚇我一跳！你又是誰啊？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저는 이번 행사 감독관을 맡게 된 론 리 교수라고 합니다.","JPN":"本イベントの監督官を務めさせていただく、ローン・リーと申します。","ENG":"I'm Professor Lone Lee, the supervisor of this event.","TWN":"我是這次活動的監察顧獨教授。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"론 리?","JPN":"ローン・リー？","ENG":"Lone Lee?","TWN":"顧獨？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"소개가 좀 늦었네요.","JPN":"紹介が遅れてしまいましたね。","ENG":"I'm sorry for this late introduction.","TWN":"介紹得有些遲了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"론 리 교수님은 저와 같은 대학 출신의 엘리트로, 지금은 관리국 미래식량개발연구부에서 10년째 연구를 진행해 오고 계신 분이세요.","JPN":"ローン・リー教授は、私と同じ大学出身のエリートで、\\n現在は管理局の未来食糧開発研究部で10年間研究を行っています。","ENG":"Professor Lone Lee is one of my brilliant colleagues from the university, who's been at the Administration's Future Food R&D Department for the past ten years.","TWN":"顧獨教授是與我同一大學畢業的精英，現在正在管理局未來代用糧研究部做研究，已經有10個年頭了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"미리 말해 두지만 단순한 열매 채취 임무라고 만만하게 보면 곤란합니다.","JPN":"先に言っておきますが、実を採取する単純な任務だと甘く見てはいけません。","ENG":"Just so you know, this isn't just a simple fruit-harvesting mission.","TWN":"話說在前頭，如果你把它看作簡單的果實採集任務而小瞧它的話，我會很困擾的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"솔로카오는 나무가 아니라 침식체들의 몸에 기생해서 자라니까요.","JPN":"ソロカオは木ではなく、侵食体の体に寄生して育つからです。","ENG":"Solocaos don't grow on trees; they're parasites growing from Corrupted Objects.","TWN":"因為獨株可可並不是樹木，而是寄生在侵蝕體身上的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐어......?","JPN":"はあ……","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이면세계의 토양은 양분이 풍족하지 않습니다.","JPN":"裏世界の土壌は養分が不十分です。","ENG":"The Counterside doesn't have fertile soil.","TWN":"異界的土壤沒有充足的養分，"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래서 솔로카오는 침식체 체내의 이터니움을 빨아먹으며 성장하도록 진화했죠.","JPN":"そのため、ソロカオは侵食体の体内にあるエタニウムを\\n吸い取って成長するように進化しました。","ENG":"So, the Solocao has evolved to feed on Eternium inside C.O.'s.","TWN":"所以獨株可可進行了進化，通過吸取侵蝕體體內的能晶來生長。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"또한 자신의 열매를 노리는 천적들을 막기 위해 숙주인 침식체를 강화하는 특수 호르몬을 분비하기도 합니다.","JPN":"また、自分の実を狙う天敵を倒すために、\\n宿主である侵食体を強化する特殊なホルモンを分泌します。","ENG":"Also, to defend itself from predators after its fruit, the plant secretes a special hormone that enhances its host C.O.","TWN":"另外，為了制止那些盯上自己果實的天敵，它們還會分泌一種特殊的荷爾蒙來強化自己的宿主侵蝕體。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그런 걸 시민들에게 먹으라고 나눠 주겠다고?","JPN":"……それを一般市民に食べさせるの？","ENG":"And you want to feed that to people?","TWN":"……你們要把這種東西分給市民吃？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 봐도 관리국이 아니라 무슨 괴식 동호회 같은 곳에서 기획한 행사 같은데......","JPN":"どう考えても管理局じゃなくて、珍味マニアが企画したイベントじゃん……","ENG":"This event sounds like it's been planned by some grotesque dining club, not the Administration.","TWN":"不管怎麼看都不像是管理局而是某些黑暗料理同好會之類策劃的活動……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리국은 이번 행사에 아주 많은 기대를 걸고 있습니다.","JPN":"管理局は、このイベントに対して大いに期待しています。","ENG":"The Administration has great expectations for this event.","TWN":"管理局對這次活動抱有很大的期待。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이번 솔로카오 나눔을 통해 이면세계의 식품을 홍보하고 시민들과의 거리를 좁히게 되면......","JPN":"このイベントを通じて裏世界の食品を知ってもらい、市民との距離が縮まれば……","ENG":"If we could advertise Counterside-derived food and close the distance between us and the public through this Solocao giveaway,","TWN":"如果能通過這次可可分享活動宣傳異界食物，並和市民們拉近距離的話……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리국이 기술을 독점하고 있다느니, 구 관리국이라는 허무맹랑한 존재를 감추고 있다느니 하는 악성 루머들은 일거에 불식될 겁니다.","JPN":"管理局が技術を独占している、または何の根拠もない\\n旧管理局という存在を隠している、などというデマは一気に消えるはずです。","ENG":"then there will be no more rumors about the Administration monopolizing new technologies and hiding the nonexistent Old Administration.","TWN":"什麼管理局獨佔了技術、藏起了荒唐的“舊管理局”，如此種種惡劣謠言也可以被一舉消除了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 수상쩍은 걸로 초콜릿을 만든다고 그게 될까......?","JPN":"こんな怪しい実でチョコレートを作ったところで、本当にそうなるかな……","ENG":"Do you really think that we could do that with chocolate made from such suspicious things?","TWN":"用這種可疑的東西做巧克力真的沒事嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"물론 관리국의 대의를 완수하기 위해서는 솔로카오만으로는 부족하죠.","JPN":"もちろん、ソロカオだけでは管理局の大義を果たすことは難しいでしょう。","ENG":"Of course, the Solocao alone isn't enough to fulfill the Administration's ultimate objective.","TWN":"當然僅憑獨株可可不足以完成管理局的大義。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래서 관리국 홍보와 행사 마케팅을 위해 최근 돌풍을 일으키고 있는 신예 카운터 팀, 하트베리를 섭외해 두었습니다.","JPN":"なので、管理局の広報やイベントのマーケティングのために、\\n最近人気を集めている新鋭カウンターチーム、ハートベリーをお招きしました。","ENG":"That's why we've scouted the up-and-coming Counter team, HRT Berry, to help promote the Administration's public image and the event itself.","TWN":"所以管理局為宣傳和活動的管理，聯繫到了最近人氣極高的新銳制裁者小隊愛心莓果。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"저, 정말인가요?! 그 하트베리?","JPN":"ほ、本当ですか！？　あのハートベリーを？","ENG":"A-are you serious?! THE HRT Berry?","TWN":"這，真的嗎？！那個愛心莓果？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 뭔데? 조교 언니도 알고 있어?","JPN":"何それ？　ユコさんも知ってるの？","ENG":"What's that? Yoonjung, do you know what that is?","TWN":"怎麼了？助手姐姐也知道他們嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"어...... 그러니까 최근 넷튜브를 무대로 침식체 사냥 방송을 하고 있는 아이돌 카운터 팀이에요.","JPN":"えっと……最近ネット配信媒体で、\\n侵食体狩りの動画を配信しているアイドルカウンターチームっす。","ENG":"Erm, they're a girl group plus Counter team that's been broadcasting its C.O. hunts on NetTube.","TWN":"嗯……就是最近正在直播平臺上做侵蝕體狩獵廣播的那個偶像制裁者小隊。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"지난번 저희 학교 축제 때도 초청했었는데......","JPN":"この前、うちの学園祭にも来てもらったんですけど……","ENG":"My school tried to bring them in for its festival last time,","TWN":"之前我們學校慶典也邀請過他們來著……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"스케쥴이 꽉 차서 섭외가 불가능할 정도였어요......","JPN":"スケジュールが全部埋まってて、オファーに苦労したっす……","ENG":"but to no avail; their schedule was so packed.","TWN":"因為她們日程排的太滿了，幾乎都聯繫不上……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아이돌 넷튜버? 침식체 사냥 방송?","JPN":"アイドルネット配信者？　侵食体狩りの動画配信？","ENG":"Girl group NetTuber? Broadcasting C.O. hunts?","TWN":"偶像 直播？ 侵蝕體狩獵廣播？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이게 다 무슨 소리야?","JPN":"一体何を言ってるんだ？","ENG":"What are you talking about?","TWN":"什麼啊？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"침식체와 싸우는 걸 장난으로 생각하는 건가?","JPN":"侵食体との戦いを遊びだと思っているのか？","ENG":"Do they think hunting C.O.'s is some sort of game?","TWN":"把和侵蝕體的戰鬥當作玩笑了嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"여기서 애들처럼 장난이나 치고 있을 만한 사람은 당신밖에 없어 보이는군요, 꼬맹이.","JPN":"裏世界で子供みたいに遊んでいそうな人は、\\nあなたしかいませんよ、お嬢さん。","ENG":"I think you're the only one here who thinks this is a game, little girl.","TWN":"看起來這裡能像小孩兒一樣開玩笑的人除了你也沒誰了，小鬼。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"꼬, 꼬맹이......?","JPN":"お、お嬢さん……だと！？","ENG":"L-little girl?","TWN":"小、小鬼？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리국의 지엄한 명령...... 아니 공문에 장난 따위는 없습니다.","JPN":"管理局の命令……いや、公文書を尊重してください。","ENG":"The Administration's strict command— I mean, the briefing had no mention of games.","TWN":"管理局的嚴令……不對，公文上可沒有開玩笑。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"알아 들었으면 즉시 지정 좌표로 출격해서 다른 차출 인원들과 합류하세요.","JPN":"わかったなら直ちに指定座標へ出撃して、他の方々と合流してください。","ENG":"If you've understood the plan, head over to the designated coordinates and join the others there.","TWN":"聽明白後就請立刻向指定座標出擊，並與其他抽調人員會合。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"할당량을 채우려면 서둘러야 할 겁니다.","JPN":"割り当てられたタスクをこなすためには、急いだ方がいいですよ。","ENG":"You'll have to hurry if you want to meet your quota.","TWN":"想完成分配量得抓緊時間了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"발렌타인 데이는 바로 내일이니까요!","JPN":"バレンタインデーは明日ですから！","ENG":"Since Valentine's Day is tomorrow!","TWN":"明天就是情人節了！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};